create table public.invoices (id uuid primary key default gen_random_uuid(), business_id uuid not null references public.businesses(id) on delete restrict, document_type text not null default 'invoice' check (document_type in ('invoice','credit_note','debit_note','refund_note','self_billed_invoice','self_billed_credit_note','self_billed_debit_note','self_billed_refund_note')), invoice_number text not null, customer_id uuid references public.parties(id) on delete set null, customer_snapshot jsonb not null default '{}'::jsonb check (jsonb_typeof(customer_snapshot) = 'object'), supplier_snapshot jsonb not null default '{}'::jsonb check (jsonb_typeof(supplier_snapshot) = 'object'), issue_date date not null, due_date date, currency char(3) not null check (currency ~ '^[A-Z]{3}$'), status text not null check (status in ('draft','sent','partially_paid','paid','overdue','void','cancelled')), subtotal_minor bigint not null check (subtotal_minor >= 0), discount_minor bigint not null default 0 check (discount_minor >= 0), tax_minor bigint not null default 0 check (tax_minor >= 0), rounding_minor bigint not null default 0, total_minor bigint not null check (total_minor >= 0), amount_paid_minor bigint not null default 0 check (amount_paid_minor >= 0 and amount_paid_minor <= total_minor), payment_terms text, notes text, issued_at timestamptz, voided_at timestamptz, voided_by uuid references public.profiles(id) on delete set null, void_reason text, created_at timestamptz not null default public.current_timestamp_utc(), updated_at timestamptz not null default public.current_timestamp_utc(), created_by uuid references public.profiles(id) on delete set null, updated_by uuid references public.profiles(id) on delete set null, version integer not null default 0 check (version >= 0), unique (business_id, invoice_number), check (total_minor = subtotal_minor - discount_minor + tax_minor + rounding_minor), check ((status not in ('void','cancelled')) or (voided_at is not null and void_reason is not null)));
create table public.invoice_items (id uuid primary key default gen_random_uuid(), invoice_id uuid not null references public.invoices(id) on delete cascade, line_number integer not null check (line_number > 0), product_service_id uuid references public.products_services(id) on delete set null, description text not null, quantity numeric(20,6) not null check (quantity > 0), unit_code text, unit_price_minor bigint not null check (unit_price_minor >= 0), discount_minor bigint not null default 0 check (discount_minor >= 0), charge_minor bigint not null default 0 check (charge_minor >= 0), tax_type_code text not null, tax_rate numeric(7,4) not null check (tax_rate between 0 and 100), tax_minor bigint not null default 0 check (tax_minor >= 0), subtotal_minor bigint not null check (subtotal_minor >= 0), total_minor bigint not null check (total_minor >= 0), classification_code text, exemption_reason text, unique (invoice_id, line_number));
create table public.invoice_status_history (id uuid primary key default gen_random_uuid(), invoice_id uuid not null references public.invoices(id) on delete restrict, from_status text, to_status text not null, reason text, changed_by uuid references public.profiles(id) on delete set null, created_at timestamptz not null default public.current_timestamp_utc());
create table public.invoice_payments (id uuid primary key default gen_random_uuid(), invoice_id uuid not null references public.invoices(id) on delete restrict, transaction_id uuid references public.transactions(id) on delete set null, amount_minor bigint not null check (amount_minor > 0), currency char(3) not null check (currency ~ '^[A-Z]{3}$'), paid_at timestamptz not null, payment_method_code text, external_reference text, notes text, created_at timestamptz not null default public.current_timestamp_utc(), unique (invoice_id, external_reference));
create table public.einvoice_submissions (id uuid primary key default gen_random_uuid(), invoice_id uuid not null references public.invoices(id) on delete restrict, attempt_number integer not null check (attempt_number > 0), environment text not null check (environment in ('sandbox','production')), status text not null check (status in ('pending','submitted','processing','completed','failed','cancelled','rejected')), myinvois_uuid text, long_id text, submitted_at timestamptz, completed_at timestamptz, response_payload jsonb, error_summary text, created_at timestamptz not null default public.current_timestamp_utc(), unique (invoice_id, attempt_number), unique (myinvois_uuid));
create table public.einvoice_validation_results (id uuid primary key default gen_random_uuid(), invoice_id uuid not null references public.invoices(id) on delete restrict, submission_id uuid references public.einvoice_submissions(id) on delete cascade, source text not null check (source in ('local','myinvois')), severity text not null check (severity in ('info','warning','error')), code text not null, field_path text, message text not null, created_at timestamptz not null default public.current_timestamp_utc());
create table public.payment_reminders (id uuid primary key default gen_random_uuid(), business_id uuid not null references public.businesses(id) on delete cascade, invoice_id uuid references public.invoices(id) on delete cascade, recipient_party_id uuid references public.parties(id) on delete set null, scheduled_for timestamptz not null, channel text not null check (channel in ('email','whatsapp','telegram','sms','manual')), message_snapshot text not null, status text not null default 'scheduled' check (status in ('scheduled','processing','sent','failed','cancelled')), idempotency_key text, created_at timestamptz not null default public.current_timestamp_utc(), updated_at timestamptz not null default public.current_timestamp_utc(), unique (business_id, idempotency_key));
create table public.reminder_deliveries (id uuid primary key default gen_random_uuid(), reminder_id uuid not null references public.payment_reminders(id) on delete cascade, attempt_number integer not null check (attempt_number > 0), status text not null check (status in ('pending','sent','failed')), provider_response jsonb, attempted_at timestamptz not null default public.current_timestamp_utc(), unique (reminder_id, attempt_number));
create trigger invoices_set_updated_at before update on public.invoices for each row execute function public.set_updated_at(); create trigger payment_reminders_set_updated_at before update on public.payment_reminders for each row execute function public.set_updated_at();
create index invoices_business_status_due_idx on public.invoices (business_id, status, due_date); create index reminders_business_schedule_idx on public.payment_reminders (business_id, status, scheduled_for);
